# MRR computation (Stripe v2024-10)
def monthly_mrr(stripe, on: date) -> Decimal:
    total = Decimal(0)
    for sub in stripe.subscriptions.list(status="active"):
        if sub.start_date.date() > on:
            continue
        if sub.canceled_at and sub.canceled_at.date() <= on:
            continue
        for item in sub["items"]["data"]:
            price = item["price"]
            qty = item["quantity"]
            cents = price["unit_amount"] * qty
            if price["recurring"]["interval"] == "year":
                total += Decimal(cents) / 12 / 100
            else:
                total += Decimal(cents) / 100
    return total
